export enum AugmentationMode {
  SAFE_PHYSICAL = 'SAFE_PHYSICAL',
  GENERATIVE_AI = 'GENERATIVE_AI'
}

export interface AugmentationEffect {
  id: string;
  name: string;
  description: string;
  promptMod: string;
}

export interface GeneratedSample {
  id: string;
  url: string;
  effect: string;
  mode: AugmentationMode;
}

export interface AppConfig {
  apiKey?: string;
  batchSize: number;
}

import { AugmentationEffect } from './types';

export const SAFE_EFFECTS: AugmentationEffect[] = [
  { id: 'sunny', name: '强光曝晒', description: '模拟夏日强光直射', promptMod: 'bright sunny daylight with high contrast and sharp shadows' },
