                  ? 'bg-purple-500/10 border-purple-500/50 ring-1 ring-purple-500/20' 
                  : 'bg-slate-800/40 border-transparent hover:border-slate-600'
                }`}
              >
                <div className={`p-2 rounded-lg ${mode === AugmentationMode.GENERATIVE_AI ? 'bg-purple-500 text-white' : 'bg-slate-700 text-slate-400'}`}>
                  <Zap size={20} />
                </div>
                <div className="text-left">
                  <div className="font-semibold text-sm">生成式引擎 (Exp)</div>
                  <p className="text-xs text-slate-400 mt-1">改变环境细节、风格迁移。可能改变细微结构，需标注校验。</p>
                </div>
              </button>
            </div>
          </section>

          {/* Advanced Settings */}
          <section className="glass-card rounded-2xl overflow-hidden">
            <button 
              onClick={() => setShowAdvanced(!showAdvanced)}
              className="w-full p-4 flex items-center justify-between text-slate-400 hover:text-white transition-colors"
            >
              <div className="flex items-center gap-2 text-sm font-medium">
                <Settings size={16} />
                高级开发者参数
              </div>
              {showAdvanced ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
            </button>

            {showAdvanced && (
              <div className="p-4 pt-0 border-t border-slate-700/50 space-y-4 bg-slate-900/50">
                <div>
                  <label className="block text-xs text-slate-500 mb-1">单次批量大小 (Max 8)</label>
                  <input 
                    type="range" min="1" max="8" step="1" 
                    value={config.batchSize}
                    onChange={(e) => setConfig({...config, batchSize: parseInt(e.target.value)})}
                    className="w-full accent-cyan-500"
                  />
                  <div className="flex justify-between text-[10px] text-slate-600">
                    <span>1 张</span>
                    <span className="text-cyan-400 font-bold">{config.batchSize} 张</span>
                    <span>8 张</span>
                  </div>
                </div>
                <div className="p-3 bg-yellow-500/10 border border-yellow-500/20 rounded-lg flex gap-3">
                  <Info className="text-yellow-500 shrink-0" size={16} />
                  <p className="text-[10px] text-yellow-500/80 leading-relaxed">
                    物理引擎会自动在后台随机混合“强光”、“大雾”、“运动模糊”等 7 种工况。生成的图片已优化为 YOLO 训练所需的对比度与噪声分布。
                  </p>
                </div>
              </div>
            )}
          </section>

          {/* Action Button */}
          <button 
            disabled={!sourceImage || isGenerating}
            onClick={startAugmentation}
            className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-3 transition-all ${
              !sourceImage || isGenerating 
              ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
              : 'neon-bg-cyan text-white hover:scale-[1.02] active:scale-95'
            }`}
          >
            {isGenerating ? (
              <>
                <Loader2 className="animate-spin" />
                正在智能扩增 ({Math.round(progress)}%)...
              </>
            ) : (
              <>
                <RefreshCcw size={20} />
                一键扩增样本
              </>
            )}
          </button>
        </div>

        {/* Right Column: Results Gallery */}
        <div className="lg:col-span-8 space-y-6">
          <section className="glass-card rounded-2xl p-6 min-h-[600px] flex flex-col">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-lg font-semibold flex items-center gap-2">
                扩增结果预览
                {samples.length > 0 && (
                  <span className="text-xs bg-cyan-500/20 text-cyan-400 px-2 py-0.5 rounded-full">
                    已生成 {samples.length} 个
                  </span>
                )}
              </h2>
              {samples.length > 0 && (
                <button 
                  onClick={() => triggerBatchDownload(samples)}
                  className="flex items-center gap-2 text-sm text-cyan-400 hover:text-cyan-300 transition-colors"
                >
                  <Download size={16} />
                  批量打包下载
                </button>
              )}
            </div>

            {samples.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {samples.map((sample, index) => (
                  <div key={sample.id} className="group relative glass-card rounded-xl overflow-hidden border border-slate-700/50 hover:border-cyan-500/30 transition-all cursor-pointer">
                    <div className="relative aspect-video overflow-hidden" onClick={() => setViewerIndex(index)}>
                      <img src={sample.url} alt={sample.effect} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                        <Maximize2 className="text-white" size={24} />
                      </div>
                    </div>
                    <div className="p-3 bg-slate-900/80 flex items-center justify-between">
                      <div>
                        <div className="text-xs font-bold text-slate-300">{sample.effect}</div>
                        <div className="text-[10px] text-slate-500 flex items-center gap-1 mt-0.5">
                          {sample.mode === AugmentationMode.SAFE_PHYSICAL ? <ShieldCheck size={10} className="text-cyan-500" /> : <Zap size={10} className="text-purple-500" />}
                          {sample.mode === AugmentationMode.SAFE_PHYSICAL ? 'Safe Mode' : 'Generative Mode'}
                        </div>
                      </div>
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          downloadImage(sample.url, `aug_${sample.id}.png`);
                        }}
                        className="p-2 bg-slate-800 rounded-lg text-slate-400 hover:text-white hover:bg-slate-700 transition-all"
                      >
                        <Download size={14} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ) : isGenerating ? (
              <div className="flex-1 flex flex-col items-center justify-center text-slate-500 gap-4">
                <div className="w-64 h-2 bg-slate-800 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-cyan-500 transition-all duration-500" 
                    style={{ width: `${progress}%` }}
                  />
                </div>
                <div className="animate-pulse text-sm font-mono">NEURAL TRANSFORMING...</div>
                <div className="grid grid-cols-2 gap-4 w-full opacity-20 pointer-events-none">
                  {[1, 2, 3, 4].map(i => (
                    <div key={i} className="aspect-video bg-slate-700 rounded-xl" />
                  ))}
                </div>
              </div>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-slate-600 gap-4">
                <div className="w-20 h-20 rounded-full bg-slate-800/50 flex items-center justify-center">
                  <AlertTriangle size={32} />
                </div>
                <p className="text-sm">暂无生成结果，请点击左侧按钮开始扩增</p>
              </div>
            )}
          </section>

          {/* Guidelines */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="glass-card rounded-xl p-4 border-l-4 border-cyan-500">
              <h3 className="text-xs font-bold text-slate-400 uppercase mb-2">训练一致性</h3>
              <p className="text-[11px] text-slate-500 leading-normal">
                物理仿真引擎生成的样本保持了像素级的边界一致性，建议直接用于标注扩增。
              </p>
            </div>
            <div className="glass-card rounded-xl p-4 border-l-4 border-purple-500">
              <h3 className="text-xs font-bold text-slate-400 uppercase mb-2">生成多样性</h3>
              <p className="text-[11px] text-slate-500 leading-normal">
                AI 引擎可生成极端的灾害环境（如冰封、火灾），适用于提高模型的泛化鲁棒性。
              </p>
            </div>
            <div className="glass-card rounded-xl p-4 border-l-4 border-green-500">
              <h3 className="text-xs font-bold text-slate-400 uppercase mb-2">数据格式</h3>
              <p className="text-[11px] text-slate-500 leading-normal">
                默认输出为 1080P 高清 PNG 格式，符合工业级巡检设备通常的分辨率要求。
              </p>
            </div>
          </div>
        </div>
      </main>

      {/* Lightbox / Viewer Modal */}
      {viewerIndex !== null && samples[viewerIndex] && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 backdrop-blur-sm animate-in fade-in duration-300">
          <button 
            onClick={() => setViewerIndex(null)}
            className="absolute top-6 right-6 p-3 text-slate-400 hover:text-white bg-slate-800/50 rounded-full transition-all hover:rotate-90"
          >
            <X size={24} />
          </button>

          {/* Navigation Controls */}
          <button 
            onClick={() => navigateViewer(-1)}
            className="absolute left-6 p-4 text-white/50 hover:text-white hover:bg-white/10 rounded-full transition-all"
          >
            <ChevronLeft size={48} />
          </button>

          <button 
            onClick={() => navigateViewer(1)}
            className="absolute right-6 p-4 text-white/50 hover:text-white hover:bg-white/10 rounded-full transition-all"
          >
            <ChevronRight size={48} />
          </button>

          <div className="max-w-5xl w-full px-12 flex flex-col items-center gap-6">
            <div className="relative group w-full">
              <img 
                src={samples[viewerIndex].url} 
                alt={samples[viewerIndex].effect} 
                className="w-full max-h-[75vh] object-contain rounded-lg shadow-2xl neon-border-blue" 
              />
              <div className="absolute top-4 left-4 px-3 py-1 bg-black/60 backdrop-blur rounded-full text-xs font-mono text-cyan-400 border border-cyan-500/30">
                {viewerIndex + 1} / {samples.length}
              </div>
            </div>

            <div className="w-full flex items-center justify-between bg-slate-900/50 p-6 rounded-2xl border border-slate-700/50">
              <div className="space-y-1">
                <div className="text-xl font-bold text-white flex items-center gap-2">
                  {samples[viewerIndex].effect}
                  {samples[viewerIndex].mode === AugmentationMode.SAFE_PHYSICAL ? 
                    <ShieldCheck size={18} className="text-cyan-500" /> : 
                    <Zap size={18} className="text-purple-500" />
                  }
                </div>
                <div className="text-sm text-slate-400">
                  策略类型: {samples[viewerIndex].mode === AugmentationMode.SAFE_PHYSICAL ? '物理仿真引擎 (100% 几何一致)' : '生成式引擎 (实验性多样性)'}
                </div>
              </div>
              <button 
                onClick={() => downloadImage(samples[viewerIndex].url, `augmented_${samples[viewerIndex].id}.png`)}
                className="flex items-center gap-2 px-6 py-3 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-xl transition-all active:scale-95"
              >
                <Download size={18} />
                下载该样本
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Footer Branding */}
      <footer className="fixed bottom-0 left-0 right-0 py-2 px-6 flex justify-between items-center text-[10px] text-slate-600 font-mono bg-[#0B0E14]/80 backdrop-blur-md border-t border-white/5">
        <div>STATUS: ENGINE_READY_FOR_DEPLOYMENT</div>
        <div className="flex gap-4">
          <span>ALGORITHM: CLOUD_AUGMENT_V2</span>
          <span>SYSTEM_TIME: {new Date().toLocaleTimeString()}</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect } from 'react';
import { 
  ShieldCheck, 
  Zap, 
  Upload, 
  Settings, 
  ChevronDown, 
  ChevronUp, 
  Download, 
  Loader2, 
  Layers,
  Info,
  AlertTriangle,
  RefreshCcw,
  CheckCircle,
  X,
  ChevronLeft,
  ChevronRight,
  Maximize2,
  Cpu,
  Code
} from 'lucide-react';
import { AugmentationMode, AugmentationEffect, GeneratedSample, AppConfig } from './types';
import { SAFE_EFFECTS, GEN_EFFECTS } from './constants';
import { fileToBase64, triggerBatchDownload, downloadImage } from './utils/imageUtils';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  // App State
  const [sourceImage, setSourceImage] = useState<string | null>(null);
  const [mode, setMode] = useState<AugmentationMode>(AugmentationMode.SAFE_PHYSICAL);
  const [samples, setSamples] = useState<GeneratedSample[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [viewerIndex, setViewerIndex] = useState<number | null>(null);
  const [config, setConfig] = useState<AppConfig>({
    batchSize: 10 // 修改默认扩增样本数量为10
  });
  const [progress, setProgress] = useState(0);

  // Keyboard navigation for viewer
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (viewerIndex === null) return;
      if (e.key === 'ArrowRight') navigateViewer(1);
      if (e.key === 'ArrowLeft') navigateViewer(-1);
      if (e.key === 'Escape') setViewerIndex(null);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [viewerIndex, samples.length]);

  const navigateViewer = (direction: number) => {
    if (viewerIndex === null) return;
    const nextIndex = (viewerIndex + direction + samples.length) % samples.length;
    setViewerIndex(nextIndex);
  };

  const getRandomEffect = (currentMode: AugmentationMode) => {
    const pool = currentMode === AugmentationMode.SAFE_PHYSICAL ? SAFE_EFFECTS : GEN_EFFECTS;
    return pool[Math.floor(Math.random() * pool.length)];
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const b64 = await fileToBase64(file);
      setSourceImage(b64);
      setSamples([]);
    }
  };

  const startAugmentation = async () => {
    if (!sourceImage) return;

    setIsGenerating(true);
    setSamples([]);
    setProgress(0);

    const service = new GeminiService();
    const newSamples: GeneratedSample[] = [];

    try {
      for (let i = 0; i < config.batchSize; i++) {
        const effect = getRandomEffect(mode);
        const resultUrl = await service.augmentImage(sourceImage, effect, mode);

        if (resultUrl) {
          newSamples.push({
            id: `sample-${Date.now()}-${i}`,
            url: resultUrl,
            effect: effect.name,
            mode: mode
          });
        }
        setProgress(((i + 1) / config.batchSize) * 100);
      }
      setSamples(newSamples);
    } catch (error) {
      console.error("Batch Augmentation Failed:", error);
      alert("生成失败，请检查 API Key 权限或网络连接。");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen pb-20 relative">
      {/* Header */}
      <header className="sticky top-0 z-40 glass-card border-b border-cyan-500/30 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-lg blur opacity-40 group-hover:opacity-100 transition duration-1000 group-hover:duration-200"></div>
            <div className="relative w-12 h-12 bg-slate-900 rounded-lg flex items-center justify-center border border-white/10">
              <Layers className="text-cyan-400" size={28} />
            </div>
          </div>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 via-blue-400 to-indigo-500">
                样本数据扩增神器
              </h1>
              <span className="hidden md:inline-block px-2 py-0.5 rounded bg-cyan-500/10 border border-cyan-500/30 text-[10px] font-bold text-cyan-400 uppercase tracking-widest">
                Industrial Grade
              </span>
            </div>
            <p className="text-[10px] text-slate-500 font-mono mt-0.5 flex items-center gap-1 uppercase tracking-tighter">
              <Cpu size={10} /> Smart Sample Augmentation Platform v2.2
            </p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className={`px-4 py-1.5 rounded-full text-xs font-bold border transition-colors shadow-lg ${
            mode === AugmentationMode.SAFE_PHYSICAL 
            ? 'border-cyan-500/50 text-cyan-400 bg-cyan-500/5' 
            : 'border-purple-500/50 text-purple-400 bg-purple-500/5'
          }`}>
            <span className="opacity-50 mr-2">核心引擎:</span>
            {mode === AugmentationMode.SAFE_PHYSICAL ? '物理仿真模式' : '生成式重绘模式'}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Upload & Controls */}
        <div className="lg:col-span-4 space-y-6">
          {/* Step 1: Upload */}
          <section className="glass-card rounded-2xl p-6 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-2 opacity-10">
              <Upload size={80} />
            </div>
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <span className="w-6 h-6 rounded bg-cyan-500/20 text-cyan-400 flex items-center justify-center text-xs">01</span>
              上传原始样本
            </h2>

            <label className="group cursor-pointer block border-2 border-dashed border-slate-700 hover:border-cyan-500/50 rounded-xl p-4 transition-all bg-slate-800/30">
              <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
              {sourceImage ? (
                <div className="aspect-video rounded-lg overflow-hidden relative">
                  <img src={sourceImage} alt="Source" className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <RefreshCcw className="text-white" />
                  </div>
                </div>
              ) : (
                <div className="aspect-video flex flex-col items-center justify-center text-slate-500 gap-2 text-center">
                  <div className="w-12 h-12 rounded-full bg-slate-800 flex items-center justify-center mb-2">
                    <Upload size={24} />
                  </div>
                  <span className="text-xs font-medium">支持拖拽或点击上传<br/>(推荐 1080P/4K 工业巡检图)</span>
                </div>
              )}
            </label>
          </section>

          {/* Step 2: Mode Selection */}
          <section className="glass-card rounded-2xl p-6">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <span className="w-6 h-6 rounded bg-cyan-500/20 text-cyan-400 flex items-center justify-center text-xs">02</span>
              选择扩增策略
            </h2>
            <div className="space-y-3">
              <button 
                onClick={() => setMode(AugmentationMode.SAFE_PHYSICAL)}
                className={`w-full p-4 rounded-xl border flex items-start gap-4 transition-all ${
                  mode === AugmentationMode.SAFE_PHYSICAL 
                  ? 'bg-cyan-500/10 border-cyan-500/50 ring-1 ring-cyan-500/20' 
                  : 'bg-slate-800/40 border-transparent hover:border-slate-600'
                }`}
              >
                <div className={`p-2 rounded-lg shrink-0 ${mode === AugmentationMode.SAFE_PHYSICAL ? 'bg-cyan-500 text-white' : 'bg-slate-700 text-slate-400'}`}>
                  <ShieldCheck size={20} />
                </div>
                <div className="text-left">
                  <div className="font-semibold text-sm">物理仿真引擎 (工业级)</div>
                  <p className="text-[11px] text-slate-400 mt-1 leading-relaxed">保证 100% 几何保真度。通过模拟光照、天气、镜头噪声，生成适用于 YOLO 训练的“无损”样本。</p>
                </div>
              </button>

              <button 
                onClick={() => setMode(AugmentationMode.GENERATIVE_AI)}
                className={`w-full p-4 rounded-xl border flex items-start gap-4 transition-all ${
                  mode === AugmentationMode.GENERATIVE_AI 
                  ? 'bg-purple-500/10 border-purple-500/50 ring-1 ring-purple-500/20' 
                  : 'bg-slate-800/40 border-transparent hover:border-slate-600'
                }`}
              >
                <div className={`p-2 rounded-lg shrink-0 ${mode === AugmentationMode.GENERATIVE_AI ? 'bg-purple-500 text-white' : 'bg-slate-700 text-slate-400'}`}>
                  <Zap size={20} />
                </div>
                <div className="text-left">
                  <div className="font-semibold text-sm">生成式引擎 (实验性)</div>
                  <p className="text-[11px] text-slate-400 mt-1 leading-relaxed">基于 Gemini 2.5 图像重绘。可生成复杂的背景迁移、极端灾害场景。注：可能改变细微物体的几何结构。</p>
                </div>
              </button>
            </div>
          </section>

          {/* Advanced Settings */}
          <section className="glass-card rounded-2xl overflow-hidden">
            <button 
              onClick={() => setShowAdvanced(!showAdvanced)}
              className="w-full p-4 flex items-center justify-between text-slate-400 hover:text-white transition-colors"
            >
              <div className="flex items-center gap-2 text-sm font-medium">
                <Settings size={16} />
                高级开发者参数
              </div>
              {showAdvanced ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
            </button>

            {showAdvanced && (
              <div className="p-4 pt-0 border-t border-slate-700/50 space-y-4 bg-slate-900/50">
                <div>
                  <div className="flex justify-between items-center mb-1">
                    <label className="block text-xs text-slate-500">批量扩增数量</label>
                    <span className="text-cyan-400 font-mono font-bold text-xs">{config.batchSize} Pcs</span>
                  </div>
                  <input 
                    type="range" min="1" max="20" step="1" 
                    value={config.batchSize}
                    onChange={(e) => setConfig({...config, batchSize: parseInt(e.target.value)})}
                    className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-cyan-500"
                  />
                  <div className="flex justify-between text-[10px] text-slate-600 mt-1">
                    <span>1</span>
                    <span>10</span>
                    <span>20</span>
                  </div>
                </div>
                <div className="p-3 bg-yellow-500/10 border border-yellow-500/20 rounded-lg flex gap-3">
                  <Info className="text-yellow-500 shrink-0" size={16} />
                  <p className="text-[10px] text-yellow-500/80 leading-relaxed">
                    物理引擎会自动在后台随机混合“强光”、“大雾”、“运动模糊”等工况。核心基于随机化管道，确保每张图的效果均不重复。
                  </p>
                </div>
              </div>
            )}
          </section>

          {/* Action Button */}
          <button 
            disabled={!sourceImage || isGenerating}
            onClick={startAugmentation}
            className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-3 transition-all relative overflow-hidden group ${
              !sourceImage || isGenerating 
              ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
              : 'neon-bg-cyan text-white hover:shadow-[0_0_20px_rgba(6,182,212,0.5)] active:scale-95'
            }`}
          >
            {isGenerating ? (
              <>
                <Loader2 className="animate-spin" />
                <span>正在神经网络变换 ({Math.round(progress)}%)...</span>
              </>
            ) : (
              <>
