                        className="w-8 h-8 flex items-center justify-center bg-slate-800 rounded-lg text-slate-400 hover:text-cyan-400 hover:bg-cyan-500/10 transition-all border border-white/5"
                      >
                        <Download size={14} />
                      </button>
                    </div>
                  </div>
                ))}
